#include<bits/stdc++.h>
using namespace std;  
const int N = 2e7;
const int B = 131;

const int Mod = 998244353;
long long pw[N];
long long pre[N], back[N];
			  int n;
int F(int l, int r)
{

	return 1ll*(pre[r] - pre[l - 1] + Mod) * pw[n - r] % Mod;
	}
int G(int l, int r)
{
	return 1ll*(back[r] - back[l - 1] + Mod) * pw[n - r] % Mod;
	}
int check(int l, int r)
{
	return F(l, r) == G(n - r + 1, n - l + 1);
}
int main(){

	string s;
	cin >> s;

	s = " " + s;
    n = s.size() - 1;	
	pw[0] = 1;
	for(int i = 1; i <= N; i++){
		pw[i] = pw[i - 1] * B %Mod;
	}
	for(int i = 1; i <= s.size(); i++){
		pre[i] = (pre[i - 1] + 1ll * s[i] * pw[i]) % Mod;
	}

	for(int i = 1; i <= s.size(); i++){
		back[i] = (back[i - 1] + 1ll * s[n - i + 1] * pw[i]) % Mod;
	}
	int l = 1, r = 1;
	int ans = 0;
	while(r <= n)
	{
		while(l - 1 >= 1 && r + 1 <= n && check(l - 1, r + 1))--l, ++r;
		++l; ++r;
		ans = max(ans, r - l + 1);
	}
	l = 1, r = 2;
	while(r <= n)
	{
		while(l - 1 >= 1 && r + 1 <= n && check(l - 1, r + 1))--l, ++r;
		++l; ++r;
		ans = max(ans, r - l + 1);
	}
	cout << ans;
}

