int d[1000003];
void dfs(int u, int d, int father){

	dep[u] = d;
	fa[u][0] = father;
	for(int i = 1; i <= 20; i++){
		fa[u][i] = fa[fa[u][i - 1]][i - 1];
	}
	for(Node x:G[u]){
		if(x.v != father)
		dfs(x.v, d + 1, u);
	}
} 
int maxx = -99;
int dfs2(int u, int father){
	for(Node x:G[u]){
		if(x.v != father)
		d[u] += dfs2(x.v, u); 
	}
	if(d[u] > maxx)
	maxx = d[u];
//	cout<<"d :: "<<d[u]<<endl;
	return d[u];
}  
int LCA(int u, int v){
	if(dep[u] < dep[v])swap(u, v);
	for(int i = 20; i >= 0; i--){
		if(dep[fa[u][i]] >= dep[v]){
			u = fa[u][i];  
		}
    }

	if(u == v) return u;
	for(int i = 20; i >= 0; i--){
		if(fa[u][i] != fa[v][i]){
			u = fa[u][i];               
			v = fa[v][i];

		}
	}
    return fa[u][0];
}
