#include<bits/stdc++.h>
using  namespace std;
const int N = 105;
struct node{ 
	vector<pair<int, int> > nxt;
}mp[N][N];
int n, m;
bool can[N][N];
int vis[N][N];
int dx[] = {0, 1, -1, 0, 0}, dy[] = {0, 0, 0, 1, -1};
int bfs(){
	queue<pair<int,int> > q;
	q.push({1, 1});
	can[1][1] = 1;
	int ans = 1;
	while(!q.empty()){
		pair<int,int> p = q.front();
		q.pop();
		int x = p.first, y = p.second;
		vis[x][y] = 1;
		if(mp[x][y].nxt.size()){
			for(pair<int,int> open : mp[x][y].nxt){
				int ox = open.first,oy = open.second;
				if(vis[ox][oy] == 2) q.push({ox,oy});
				if(can[ox][oy] == false){
					can[ox][oy] = true;
					ans++;
				}
			}
		}
		for(int i = 1; i <= 4; i++){
			int nx = x + dx[i],ny = y + dy[i];
			if(nx < 1 || nx > n || ny < 1 || ny > n || vis[nx][ny] != 0)continue;
			if(can[nx][ny] == true)q.push({nx, ny});
			else vis[nx][ny] = 2; 
		}
	}
	return ans;
}
int main(){
	cin >> n >> m; 
	for(int i = 1; i <= m; i++){
		int x1, y1, x2, y2;
		cin >> x1  >> y1 >> x2 >> y2;
		mp[x1][y1].nxt.push_back({x2, y2});
	}
	cout << bfs(); 
}

