#include<bits/stdc++.h> //万能头
#define int long long  //十年OI一场空，不开long long见祖宗                  
using namespace std; //标准命名空间     
const int N = 5e6 + 7; //数组边界 
int cnt = 0;//记录有多少个假话 
int n,k;
int fa[N];
int find(int x){
	if(fa[x] == x) return x;  
	  //如果他的祖宗是他自己，就返回他自己 
	fa[x]=find(fa[x]); 
	return fa[x]  ;   //否则就继续往上找 
}
//我们定义fa[x]为自己的同类，fa[x + n]为自己的猎物，fa[x + n + n] 为自己的天敌 
signed main(){               //signed = int 主函数
	ios::sync_with_stdio(false);
	cin.tie(0);
	cout.tie(0); //关闭流同步
	cin >> n >> k;//输入 
	for(int i = 0; i < N; i++) fa[i] = i; //先将祖宗指向自己(初始化)
	while(k--){
		int op,x,y;//op = 1 or 2
		cin >> op >> x >> y;
		if(x > n or y > n){    //如果x或y不在食物链（＞N） 
			cnt++;   //假话个数加一 
		//	cout << op << ' ' << x << ' ' << y << endl;
			continue;    //跳过 
		} 
		if(op == 1){
			if(find(x + n) == find(y) or find(x) == find(y + n)){        //如果y是自己的猎物或自己是y的猎物，则不满足x是y的同类 
			//	cout << op << ' ' << x << ' ' << y << endl;
				cnt ++;   //假话个数加一 
				continue;  //跳过 
			} 
			//否则自己的猎物就是同类的猎物，自己的天敌是同类的天敌，自己的同类是同类的同类；
			fa[find(x)] = find(y); 
			fa[find(x + n)] = find(y + n);
			fa[find(x + n + n)] = find(y + n + n);
		}
		if(op == 2){
			if(x == y or find(x) == find(y + n) or find(x) == find(y)){    //如果y是自己的同类或y的猎物是x或表示为自己吃自己，则不满足x吃y
			//	cout << 3 << endl;
				cnt++; //假话个数加一 
				continue; //跳过 
			}
			else{
				fa[find(x)] = find(y + n + n);
				fa[find(x + n)] = find(y);
				fa[find(x + n + n)] = find(y + n); 	
			}
			//否则x的猎物是y的同类，x的同类是y的天敌，x的天敌是y的猎物

		}
	}
	cout << cnt << endl; //输出答案 
}

#include<bits/stdc++.h>
using namespace std;
namespace  Mine
{
	double ans,cnt;
int  vis[33], n, x[23], y[23] ;
double r[33];
int lx, ly, rx, ry;
void dfs(int k){
	    if(k > n){
	    	if(cnt < ans)ans = cnt;
	    	return;
		}
		for(int i = 1; i <= n; i++){
			if(vis[i] == 0){
			  r[i] = min(x[i], min(y[i], min(rx - x[i], ry - y[i])));
			     //cout << r[i] << endl;	
			  for(int j = 1 ; j <= n; j++){
			  	if(vis[j] == 0)continue;
			  	double tmp;
			  	tmp = sqrt((x[i] - x[j]) * (x[i] - x[j]) + (y[i] - y[j]) * (y[i] - y[j]));
			  	if(r[i] > tmp - r[j]) r[i] = tmp - r[j]; 
			    }
				if(r[i]<0)r[i]=0;
			  	cnt -= r[i] * r[i] * acos(-1);
			  	vis[i] = 1;
			  	dfs(k + 1);
			  	vis[i] = 0;
			  	cnt += r[i] * r[i] * acos(-1);

			}

		}

}
int xn, yn, xm, ym;
int main(){
	cin >> n;	
	cin >> xn >> yn >> xm >> ym;

    lx = min(xn, xm);
    rx = max(xn, xm);
    ly = min(yn, ym);
    ry = max(yn, ym);
    rx -= lx;
    ry -= ly;
    ans = cnt = rx * ry;
	for(int i = 1; i <= n; i++){
		cin >> x[i] >> y[i];
		x[i] -= lx;
		y[i] -= ly;
	}   
	dfs(1);
	cout << int(round(ans));
	return 0;
}
}

