int dfs(int time, int tree, int k){
	if(time > n)
	return 0;
	if(f[time][tree][k] != -1)return f[time][tree][k];	
	int tmp1 = 0, tmp2 = 0;
	if(k < w){
		if(tree == 1)tmp1 = dfs(time, 2, k + 1);
