	queue<int> q;
	q.push(x);
	while(!q.empty()){
		int u = q.front();
		q.pop();             

	    if(u == y)return dis[u];
		int v = u + 1;
		if(!visit[v] && 0 < v && v < 500000){
			dis[v] = dis[u] + 1;
			visit[v] = 1;
			q.push(v);				
		}	
		v = u - 1;
		if(!visit[v] && 0 < v && v < 500000){
			dis[v] = dis[u] + 1;
			visit[v] = 1;
		 	q.push(v);
		 }
		v = 2 * u;
		if(!visit[v] && 0 < v && v < 500000){
			dis[v] = dis[u] + 1;
			visit[v] = 1;
			q.push(v); 
	}

	}
}
